if __name__ == "__main__":
    print("=== JWT Auth Flask API ===")
    print("Endpoints:")
    print("  POST /auth/register  - Register (JSON: username, password)")
    print("  POST /auth/login     - Login    (JSON: username, password) -> token")
    print("  POST /auth/refresh   - Refresh token (Authorization: Bearer <token>)")
    print("  GET  /protected      - Example protected route")
    print("  GET  /users/me       - Current user profile")
    print()
    app.run(debug=True, port=5000)